<?php

namespace App\Ai\Tools\Builder;

use App\Ai\Tools\Builder\Concerns\EnrichesCatalogEntries;
use Illuminate\Contracts\JsonSchema\JsonSchema;
use Laravel\Ai\Contracts\Tool;
use Laravel\Ai\Tools\Request;

/**
 * Catalog of UI block types Claude is allowed to put in a page. Hard-coded so
 * the model cannot invent unsupported types — the runtime would refuse to
 * render them anyway, this gives Claude the same context up-front.
 */
class ListAvailableComponentsTool implements Tool
{
    use EnrichesCatalogEntries;

    public function name(): string
    {
        return 'list_available_components';
    }

    public function description(): string
    {
        return 'List the UI block types you may use inside page.blocks. The runtime can only render these types — any other type will fail validation. Each entry adds `params` (required/optional props + allowed enum values), an `example` skeleton, and the `definition` name to drill into with get_manifest_schema.';
    }

    public function schema(JsonSchema $schema): array
    {
        return [];
    }

    public function handle(Request $request): string
    {
        $catalog = [
            ['type' => 'container', 'description' => 'Layout group. direction: row = equal side-by-side columns that fill the width and stretch to a shared height; column = stacked; masonry = pack children at their NATURAL height into responsive columns, filling vertical gaps (a true masonry wall for INDEPENDENT cards of varying height — reading order is column-major). Plus gap and nested blocks.'],
            ['type' => 'text', 'description' => 'Paragraph of body text. Has content (string) and size (xs|sm|base|lg|xl).'],
            ['type' => 'heading', 'description' => 'Section heading. Props: content, level (1-6, semantic), and optional size (sm|md|lg|xl|2xl|display) to override the visual size. Defaults are already website-scaled (h2 ≈ 2xl/3xl); use size="display" for a big landing section title or size="sm" to tone one down.'],
            ['type' => 'divider', 'description' => 'Horizontal rule, no props.'],
            ['type' => 'spacer', 'description' => 'Vertical gap. Has size (sm|md|lg|xl).'],
            ['type' => 'table', 'description' => 'Tabular list of records. Requires data_source ({object_id, filter?, sort?}) and columns[]. Each column is EITHER a data column `{id, field_id, label_override?, width?}` OR an action column `{id, type:"action", label, icon?, variant? (primary|secondary|danger|ghost), confirm? {title, message}, on_click: [actions]}`. Inside on_click you can reference the clicked row via {{row.id}} and {{row.data.<slug>}} — e.g. an "update_record" action with record_id_expression="{{row.id}}" and values={completada:true} toggles a checkbox per row. The `icon` prop accepts a named icon (call list_available_icons) or an emoji. Use action columns for inline Mark / Edit / Delete buttons; do NOT try to use formula fields or extra buttons outside the table. Optional `pagination` {page_size: 10-200} adds a client-side pager over the loaded rows — raise data_source.limit to load enough rows to page through.'],
            ['type' => 'data_grid', 'description' => 'Editable table: record rows whose cells can be edited inline and saved (update_record) without leaving the page. Requires data_source ({object_id, filter?, sort?}) and columns[] ({field_id, label_override?, editable?}). Editable cells render a type-appropriate input (text/number/select/checkbox/date); computed fields (formula/lookup/rollup), relations and files are always read-only. Use `table` for read-only lists with row-action buttons; use data_grid when users edit values in place.'],
            ['type' => 'record_detail', 'description' => 'Read-only view of ONE record\'s fields (a definition list of label/value pairs, formatted by field type). Requires object_id, record_id_expression (resolves to the record id — e.g. {{params.id}} on a detail page, or {{row.id}}) and fields[] ({field_id, label_override?}). The detail half of a master-detail layout: put a table on the left whose row action navigates with the id as a param, and a record_detail on the right.'],
            ['type' => 'related_list', 'description' => 'A record\'s children: a compact read-only table of the records of ANOTHER object that point back to this one via a relation. Requires object_id (the child object), via_relation_field_id (a relation field ON the child object pointing to the parent), parent_id_expression (resolves to the parent id — e.g. {{params.id}}) and columns[] ({field_id, label_override?}). Pair with record_detail on a detail page, e.g. an Order plus its Order Items.'],
            ['type' => 'stat', 'description' => 'Single numeric KPI card. Requires label, query ({object_id, filter?}), aggregation (count|sum|avg|min|max|distinct_count|median|p90|p95). distinct_count (unique values of ANY field, e.g. unique customers) and median/p90/p95 (percentiles of a numeric field, e.g. p95 resolution time) need field_id; sum/avg/min/max need a numeric field_id; count needs none. Optional: format, icon (emoji), and a TREND chip — set `compare` (a second query, e.g. the previous period via a sys_created_at filter) and `delta_good` (up|down: which way is good) to show the % change with an up/down arrow coloured green/red. RATIO: set `ratio_denominator` {query, aggregation, field_id?} to make the value (this block\'s aggregate) ÷ (the denominator\'s) — a rate like win rate (won ÷ closed) or conversion; use format="percentage" (no trend chip on ratios). INLINE SPARKLINE: set `spark` {data_source (query), x_field_id (a date, bucketed by day), y_field_id?, aggregation? (default count), color?} to draw a small trend line beside the value — the history behind the number (e.g. daily spend behind "Total spend"). Add `compare_label` (e.g. "vs período anterior") for a muted caption next to the trend chip.'],
            ['type' => 'insight', 'description' => 'A callout card for an insight, conclusion, recommendation or warning. Props: variant (insight|recommendation|conclusion|positive|warning|risk — sets colour + icon), title (required), body?, icon? (emoji override), metric? (a static highlighted figure like "+34%"), and `compute?` for a LIVE figure. `compute` = {query, aggregation (count|sum|avg|min|max|distinct_count|median|p90|p95), field_id?, format?, compare? (a second query, e.g. previous period), delta_good? (up|down)} — the runtime aggregates it and shows the result as the metric WITH a trend chip vs compare, overriding any static metric. Use `compute` so the card states a real, current number (e.g. title "Resolución vs período anterior" + compute median resolution time with a previous-period compare) instead of a hand-written one. Stack several, or pair each with its chart.'],
            ['type' => 'stepper', 'description' => 'A progress stepper for an ordered process (order status, onboarding). Props: steps[] ([{label, description?}], 2-12), current_step (0-based index of the active step — earlier = done with a check, later = upcoming), orientation (horizontal|vertical, default horizontal). Static/display-only — pair with a workflow or field to reflect real state.'],
            ['type' => 'badge', 'description' => 'A small status pill/tag. Props: label (required), variant (neutral|accent|info|success|warning|danger — colour preset), color? (custom hex, overrides variant), icon? (named icon or emoji). Use for a single status/label chip on a page; for per-row status in a table prefer a single_select column (it already renders coloured chips).'],
            ['type' => 'alert', 'description' => 'A static callout/notice on a page or form. Props: variant (info|success|warning|danger — colour + default icon), title (required), body?, icon? (emoji or named icon), dismissible? (shows a close button). Use for guidance or status ("Read this before submitting", "Your trial ends soon") — distinct from `insight`, which is for dashboard conclusions.'],
            ['type' => 'avatar', 'description' => 'A person/entity avatar: an image (src) or auto initials from `name` on an accent tile, with optional label + caption beside it. Props: src?, name?, label?, caption?, size (sm|md|lg|xl), shape (circle|square). Use in headers, team/profile sections, or beside a record_detail.'],
            ['type' => 'breadcrumb', 'description' => 'A breadcrumb trail for nested navigation. Props: items[] ([{label, href?}], 1-8) — the last item renders as the current page (no link). Place at the top of a detail/sub page.'],
            ['type' => 'carousel', 'description' => 'An image/content slider with prev/next arrows + dots. Props: items[] ([{image (URL, required), title?, caption?, href?}], 1-20), autoplay? (default false), interval_ms? (2000-15000), height_px? (160-720, default 360). Use for galleries, highlights or hero rotations on content pages.'],
            ['type' => 'form', 'description' => 'User-editable form. Requires object_id and mode (create|edit). Optional: fields ([{field_id, label_override?, default_expression?, readonly_expression?, visible_if?, required_if?}]), submit_label, on_submit (action sequence), on_cancel. mode=edit also requires record_id_expression. Per-field options: `default_expression` pre-fills the initial value (resolved server-side; use {{current_user.id}}, {{today()}}, {{now()}}). `readonly_expression` resolves to a boolean that disables the field. `visible_if` / `required_if` are STRUCTURED conditions {field_id, op, value} evaluated live against another field of THIS form — op ∈ eq|neq|gt|gte|lt|lte|in|not_in|contains|is_null|is_not_null|is_truthy|is_falsy (omit value for is_* ops, array for in/not_in). Example: show "motivo" only when estado == "rechazado" → visible_if {field_id:"<estado fld id>", op:"eq", value:"rechazado"}. Hidden fields are not submitted; required_if is enforced before submit.'],
            ['type' => 'button', 'description' => 'Clickable button that fires on_click (action sequence). Requires label and on_click. Optional: variant (primary|secondary|danger|ghost), size, icon, confirm ({title, message}).'],
            ['type' => 'filter_bar', 'description' => 'Page-level filter controls that drive {{params.*}}. controls[] each {param (URL param name), type (search|select|date_range), label?, placeholder?, options?, default?}. Wire a data block to react by giving its data_source.filter a condition with value_expression "{{params.<name>}}" (e.g. {op:"contains", field_id, value_expression:"{{params.q}}"} for a search box, {op:"eq", field_id:<status>, value_expression:"{{params.status}}"} for a select). An empty value is ignored, so the unfiltered set shows. DATE RANGE: a `date_range` control renders preset window pills (Hoy/7d/30d/90d/Año/Todo; override with options[{value,label}]) and writes the preset KEY; react with {op:"gte", field_id:<a date field>, value_expression:"{{range_start(default(params.<param>, \'30d\'))}}"} — range_start() maps the key to the window-start date and \'all\' clears it. Set default:"30d" to preselect. When a dashboard\'s data has a date field, ALWAYS add one date_range control and wire every time-relevant block to it.'],
            ['type' => 'modal', 'description' => 'Dialog opened/closed by open_modal/close_modal actions. Props: title (string), description? (string — sub-title that also satisfies the a11y aria-describedby; if omitted, a sr-only fallback is rendered), size (sm|md|lg), blocks (nested, typically a form). Reference its id from a button via open_modal.'],
            ['type' => 'chart', 'description' => 'Visualisation of aggregated records. Requires chart_type and data_source (query block) + aggregation (count|sum|avg|min|max). chart_type: bar (vertical columns), hbar (horizontal bars/progress), line, area, pie, donut, radar (3+ categories on radial axes — good for multi-metric profiles), scatter (raw x/y points — set x_field_id AND y_field_id, both numeric). For sum/avg/min/max pass y_field_id (numeric). Use group_by_field_id (typically single_select) to split the series; without it the whole result becomes one bucket. hbar suits long labels; bar suits few categories; radar plots group_by_field_id categories as the axes; set series_field_id to overlay MULTIPLE entities as separate polygons on the same axes (compare 2-3 entities across the dimensions, e.g. seller → SLA/volume/resolution); scatter suits correlation between two numeric fields; treemap suits part-to-whole SEGMENTATION (each group_by bucket is a rectangle sized by its share); sankey suits FLOW between two categories (set group_by_field_id as the SOURCE column and series_field_id as the TARGET column — each source→target pair becomes a ribbon sized by the aggregated value; e.g. motivo → responsable, or channel → outcome); pareto suits ROOT-CAUSE / concentration analysis (the classic top-N question): descending bars of sum/avg(y_field_id) per group_by_field_id category PLUS a cumulative-%% line on a right 0-100%% axis with an 80%% tick — set group_by_field_id (a real dimension, never a date) + y_field_id + aggregation sum, e.g. causa raiz -> total_tickets; box suits the DISTRIBUTION of a numeric field per category — set group_by_field_id (the category axis) and y_field_id (the numeric field); it draws one box-and-whisker per group (Q1–Q3 box, median line, 1.5·IQR whiskers, outlier dots) and IGNORES aggregation, so use it to compare spread/skew, e.g. resolution days per responsable. For a bar chart you can split each category into segments by a SECOND field via series_field_id, and set stacked:true to stack them (default is grouped/side-by-side) — e.g. group_by=month, series_field_id=status. Charts use count|sum|avg|min|max only; for distinct_count/median/p90/p95 use a stat or metric_grid KPI instead. COMBO + DUAL AXIS: set `series` (1-4 items) to overlay several typed measures on one shared X (group_by_field_id/x_field_id) — each item {type: bar|line|area, aggregation, field_id?, label?, axis: left|right, color?}. Use axis:"right" for a measure on a different scale (secondary axis), e.g. revenue bars (left) + conversion-rate line (right). When `series` is set the chart renders as a combo and top-level chart_type/aggregation/y_field_id are ignored (still set chart_type, e.g. "bar"). TIME AXIS: for any chart (combo or not) whose X / group_by is a date/datetime (incl. sys_created_at), set `bucket` (day|week|month|quarter|year) to group it into periods shown one point each, sorted chronologically — e.g. revenue by month = group_by=sys_created_at + bucket="month".'],
            ['type' => 'word_cloud', 'description' => 'Word cloud sized by frequency. Requires data_source and field_id (the field whose values become words — e.g. a single_select/multi_select category or a short text field). Optional: label, max_words (5-120, default 40). Each distinct value is sized by how often it appears.'],
            ['type' => 'flow', 'description' => 'Flowchart / process diagram (static — you define the steps). Props: steps[] each {label, description?, icon? (emoji)}, direction (row|column, default row), label?. Renders connected steps with numbered nodes and arrows. Use for processes, pipelines, "how it works" sections.'],
            ['type' => 'kanban', 'description' => 'Kanban board. Requires data_source, group_by_field_id (must be single_select — its options become the columns) and card_title_field_id. Optional: card_meta_fields ([{field_id}]) for secondary lines on each card, and editable (bool) — when true, cards can be dragged between columns and the move writes the new value to the group_by field (update_record) and refreshes.'],
            ['type' => 'calendar', 'description' => 'Month calendar of records. Requires data_source, date_field_id (date|datetime field — drives when each event lands) and title_field_id. Optional: color_field_id (single_select) — each event picks up the option color as its accent.'],
            ['type' => 'markdown', 'description' => 'Static rich text rendered from a markdown string. Just one prop: content. Good for intros, instructions, FAQs, hero copy. Supports headings, lists, bold/italic, links, code blocks, tables and blockquotes.'],
            ['type' => 'image', 'description' => 'Static image from a URL. Props: src (required), alt, fit (contain|cover|fill), rounded, max_height (px). For real-looking photos on content/marketing pages use a stable stock URL: "https://picsum.photos/seed/<word>/1200/800" — pick a different <word> per image (e.g. solar, forest, ocean) so each is distinct. Do NOT use source.unsplash.com (that endpoint is retired and returns errors). Always set a descriptive alt. NOT for record attachments yet.'],
            ['type' => 'hero', 'description' => 'Full-width hero banner for the top of a landing/marketing page. Props: title (required), subtitle?, background_image? (stock URL like https://picsum.photos/seed/<word>/1600/900 — NOT source.unsplash.com, which is retired), overlay? (bool, default true — darkens the image so the white hero text stays readable), align? (left|center), min_height? (96-900 px), cta? {label, on_click:[actions]}, and a brand `style.gradient`/`style.background` for an on-brand banner (no image needed). Use a big centred hero (min_height 400+) as the FIRST block of a website home page for visual impact; on a DASHBOARD use a COMPACT LEFT hero instead (align:"left", min_height ~110-140, a brand style.gradient) so it does not steal space from the data.'],
            ['type' => 'feature_grid', 'description' => 'Responsive grid of feature/benefit cards. Props: columns? (2|3|4, default 3), items[] each {icon? (an EMOJI like 🌍⚡🌱), title, description?}. Cards are transparent and inherit the section colour, so place inside a styled section. THE way to do a "3 features / benefits / steps" row — do not fake it with split_view.'],
            ['type' => 'cta', 'description' => 'Call-to-action band: a centred title + subtitle + one button. Props: title (required), subtitle?, align? (left|center), button? {label, on_click:[actions]}. Put it (usually with a bold style.background or style.gradient + style.full_bleed) as the LAST section to drive an action.'],
            ['type' => 'stat_band', 'description' => 'A row of big headline numbers. Props: items[] each {value (e.g. "1.1°C", "51B"), label}. The numbers use the brand accent. Great right under the hero to show impact/scale.'],
            ['type' => 'testimonials', 'description' => 'Quote cards. Props: columns? (1|2|3, default 3), items[] each {quote, author?, role?, avatar? (URL)}. Builds trust on landing pages.'],
            ['type' => 'faq', 'description' => 'Accordion of questions. Props: items[] each {question, answer}. First item open by default; one expands at a time.'],
            ['type' => 'pricing', 'description' => 'Pricing tiers. Props: columns? (2|3|4), tiers[] each {name, price (e.g. "$29"), period? ("/mes"), featured? (bool — highlighted with accent), features? [strings], cta? {label, on_click:[actions]}}.'],
            ['type' => 'metric_grid', 'description' => 'Several stats laid out in a responsive grid. Props: columns (1-6, default 3) and items[] where each item has {id, label, query, aggregation (count|sum|avg|min|max|distinct_count|median|p90|p95), field_id?, format?, icon?, compare?, delta_good?, spark?, compare_label?} — same shape as a stat block (including distinct_count/percentiles, the optional trend chip, `ratio_denominator` for rate KPIs, and `spark` for an inline trend line beside the value). Prefer this over multiple stat blocks side by side, e.g. as the KPI row at the top of a dashboard.'],
            ['type' => 'sparkline', 'description' => 'Compact line showing a trend without axis labels. Requires data_source. Optional: x_field_id (typically a date, used to bucket+sort), y_field_id (numeric, defaults to count(*)), aggregation (default count), color (hex), label.'],
            ['type' => 'gauge', 'description' => 'Half-circle gauge showing one aggregate against a max_value (required). Props: label, query, aggregation (count|sum|avg|min|max|distinct_count|median|p90|p95), field_id (required for non-count), max_value (number — the 100% mark), format (number|currency|percentage), color (hex). Use for goals/quotas.'],
            ['type' => 'progress', 'description' => 'Linear progress bar showing one aggregate against a max_value (required) — same data shape as gauge but a horizontal bar, compact and stacks cleanly in a column for several goals at once. Props: label, query, aggregation (count|sum|avg|min|max|distinct_count|median|p90|p95), field_id (required for non-count), max_value, format (number|currency|percentage), color (hex).'],
            ['type' => 'pivot', 'description' => 'A 2-D MATRIX: rows x columns, one aggregate per cell (revenue by region AND month). Requires data_source, group_by_field_id (the rows), column_field_id (the columns) and aggregation (count|sum|avg|min|max|distinct_count). Optional: y_field_id (required for non-count), bucket / column_bucket (day|week|month|quarter|year — truncate a date row/column; a date column WITHOUT a bucket makes every timestamp its own column), format, label, description. Set mode:"cohort" for a RETENTION table: the columns stop being calendar dates and become the offset from each row\'s own start (Mes 0, Mes 1...), and each cell becomes the % of that cohort still present — so cohorts born in different months are comparable. A cohort needs column_bucket. Classic retention: rows = signup date (bucket month), columns = activity date (column_bucket month), aggregation = distinct_count over the customer field.'],
            ['type' => 'heatmap', 'description' => 'GitHub-style activity heatmap. Requires data_source and date_field_id. Optional: weeks (4-104, default 26), color (hex). Each cell is one day; intensity is the row count for that day.'],
            ['type' => 'timeline', 'description' => 'Vertical timeline sorted by date (newest first). Requires data_source, date_field_id (date|datetime) and title_field_id. Optional: description_field_id (long_text|string), color_field_id (single_select). Good for activity logs, notes, comms history.'],
            ['type' => 'gantt', 'description' => 'Horizontal schedule: one bar per record spanning start_field_id → end_field_id (both date/datetime) on a shared time axis. Requires data_source, start_field_id, end_field_id, title_field_id. Optional: label, color_field_id (single_select colours each bar). Good for projects, leases, bookings. Use calendar for single-date events, timeline for a chronological list.'],
            ['type' => 'funnel', 'description' => 'Conversion funnel — each stage is its own aggregate query (likely the same object with a different filter). Props: label, stages[] where each stage has {id, label, query, aggregation (count|sum|avg), field_id?, color?}. The first stage is the 100% baseline; later stages show conversion %.'],
            ['type' => 'map', 'description' => 'Interactive map (maplibre + free OpenFreeMap tiles, no API key). Requires data_source, lat_field_id and lng_field_id (both number fields). Optional: popup_field_id (text shown on marker click), color_field_id (single_select), height_px (200-800, default 400). The map auto-fits to the markers.'],
            ['type' => 'tabs', 'description' => 'Tabbed panel. Each tab has its own nested blocks array. Props: tabs[] ([{id, label, icon?, blocks[]}]), default_tab_id?. Use to organise a busy page (e.g. tabs for Overview / Records / Settings).'],
            ['type' => 'accordion', 'description' => 'Collapsible sections. Props: sections[] ([{id, title, default_open?, blocks[]}]), allow_multiple? (default false — opening one closes the others). Use for FAQs, advanced settings, optional details.'],
            ['type' => 'split_view', 'description' => 'Two-column layout. Props: left_blocks[], right_blocks[], left_fraction? (1-11, default 4 → 1/3 left, 2/3 right). Use for master-detail layouts (e.g. left a table, right a summary). MVP is static — no row-click linking between sides yet.'],
            ['type' => 'card_grid', 'description' => 'Records rendered as cards in a responsive grid (alternative to table when visual scan beats density). Requires data_source and title_field_id. Optional: columns (1-6, default 3), subtitle_field_id, image_field_id (string field with a URL), meta_fields[]. Set `on_click` (an action_sequence) to make each card tappable — it runs with {{row.id}} / {{row.data.<slug>}} of that card and shows a small action button (override its icon with `action_icon`). THE primitive for a product picker that adds to an order: on_click create_record a line with values {<parent_rel>:"{{params.<x>}}", <item_rel>:"{{row.id}}", qty:1} then refresh.'],
            ['type' => 'multi_step_form', 'description' => 'Wizard form that splits fields across N ordered steps. Requires object_id, mode (create|edit), and steps[] where each step has {id, title, description?, fields[{field_id, label_override?, default_expression?, readonly_expression?, visible_if?, required_if?}]} (same per-field options as the `form` block). Optional: show_progress (default true) for the numbered indicator at the top, submit_label, cancel_label, on_submit (action sequence), on_cancel. mode=edit also requires record_id_expression. Use this instead of `form` when you have 8+ fields or a logical grouping (Personal info → Address → Preferences). Required fields are validated locally before advancing; the backend re-checks everything on submit. Each field_id can appear in at most one step.'],
        ];

        return json_encode([
            'components' => $this->withSchema('component', $catalog),
            'site' => 'A website should have site chrome + a cohesive look, set in manifest `settings`: `accent` ("#RRGGBB" — the ONE brand colour; drives all buttons/links/highlights, set it once per site), `font` (sans|serif|rounded|mono), `theme` (light|dark, default light), `brand` {name, logo? (URL), cta? {label, href}} → renders a sticky site header, and `footer` {text?, links?[{label,href}]} → renders a site footer. Always set `accent` and `brand` for a real website so it does not look like a bare document.',
            'style' => 'EVERY block accepts an optional `style` object to turn it into a section: {padding, margin (none|sm|md|lg), background "#RRGGBB", gradient {from,to,direction:to-b|to-r|to-br|to-tr}, color "#RRGGBB", max_width (sm|md|lg|full), full_bleed (bool)}. Build alternating sections by wrapping a `container` with style.padding="lg" + a background (flat `background` or a `gradient` — keep gradient from/to in the same tonal family). TEXT CONTRAST IS AUTOMATIC: setting background/gradient auto-picks a legible text colour (dark on light, light on dark) — do NOT set `color` and do NOT also put a background on inner heading/markdown. Set style.full_bleed=true on top-level coloured sections so the band spans edge-to-edge. Set style.max_width="md" on text sections so lines stay readable and centre on wide screens. Use this for visual rhythm — never leave a content page as plain text.',
        ], JSON_THROW_ON_ERROR);
    }
}
